12: const Diacritic = enum(u8) {
13:     empty, // nguyên âm, không dấu.
14:     circumflex, // dấu nón: â, ô, ê.
15:     horn, // dấu móc: ư, ơ.
16:     breve, // dấu ă.
17:     bar, // dấu gạch: đ.
18: };
