20: const Tone = enum(u8) {
21:     level, // thanh ngang, không dấu.
22:     rising, // sắc.
23:     falling, // huyền.
24:     dipping_rising, // hỏi.
25:     rising_glottalized, // ngã.
26:     falling_glottalized, // nặng.
27: };
