29: const Span = struct {
30:     // Alphabet ASCII character, could be lowercase or uppercase.
31:     base: u8,
32:     // By default, it's plain alphabet character.
33:     diacritic: Diacritic = .empty,
34:     // By default, no tone is placed.
35:     tone: Tone = .level,
36: 
37:     // Create a Span with plain alphabet character, no diacritic, no tone.
38:     fn init(base: u8) Span {
39:         return Span.init_diacritic_tone(base, .empty, .level);
40:     }
41: 
42:     // Create a Span with diacritic, no tone.
43:     fn init_diacritic(base: u8, diacritic: Diacritic) Span {
44:         return Span.init_diacritic_tone(base, diacritic, .level);
45:     }
46: 
47:     fn init_diacritic_tone(base: u8, diacritic: Diacritic, tone: Tone) Span {
48:         // Only allow a-zA-Z.
49:         assert(std.ascii.isAlphabetic(base));
50: 
51:         // Only allow a valid Vietnamese alphabet combinations.
52:         switch (diacritic) {
53:             // All alphabet is allowed without diacritic.
54:             .empty => {},
55:             // Only a, o, e are valid with circumflex.
56:             .circumflex => switch (base) {
57:                 'A', 'E', 'O', 'a', 'e', 'o' => {},
58:                 else => unreachable,
59:             },
60:             // Only u, o are valid with horn.
61:             .horn => switch (base) {
62:                 'O', 'U', 'o', 'u' => {},
63:                 else => unreachable,
64:             },
65:             // Only a is valid with breve.
66:             .breve => switch (base) {
67:                 'A', 'a' => {},
68:                 else => unreachable,
69:             },
70:             // Only d is valid with bar.
71:             .bar => switch (base) {
72:                 'D', 'd' => {},
73:                 else => unreachable,
74:             },
75:         }
76: 
77:         // Only allow tone on valid Vietnamese vowels based on Vietnamese rules.
78:         switch (tone) {
79:             // All alphabet is allowed with level.
80:             .level => {},
81:             // All vowels is allowed with remaining tones.
82:             .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized => switch (base) {
83:                 'A', 'E', 'I', 'O', 'U', 'Y', 'a', 'e', 'i', 'o', 'u', 'y' => {},
84:                 else => unreachable,
85:             },
86:         }
87: 
88:         return .{ .base = base, .diacritic = diacritic, .tone = tone };
89:     }
90: 
91:     // Compare the span with a base character (ignore case) and diacritic, tone is ignored.
92:     fn equals_ignore_case_and_tone(self: Span, base: u8, diacritic: Diacritic) bool {
93:         // Base must be alphabet letters.
94:         assert(std.ascii.isAlphabetic(base));
95: 
96:         return std.ascii.toUpper(self.base) == std.ascii.toUpper(base) and self.diacritic == diacritic;
97:     }
98: 
99:     // Compare only base character, ignore other aspects.
100:     fn equals_base(self: Span, base: u8) bool {
101:         // Base must be alphabet letters.
102: 
103:         return std.ascii.toUpper(self.base) == std.ascii.toUpper(base);
104:     }
105: };
